create extension if not exists pgcrypto;
create type user_role as enum ('candidate','recruiter','organisation_admin','platform_admin');
create type organisation_type as enum ('recruitment_agency','school','direct_employer','platform_admin');
create type verified_status as enum ('unverified','pending','verified','rejected');
create type recruiter_type as enum ('agency_recruiter','school_recruiter','independent_recruiter');
create type employment_search_status as enum ('actively_looking','open_to_offers','not_looking');
create type profile_visibility as enum ('private','limited','public');
create type job_status as enum ('draft','live','paused','closed','filled','expired');
create type salary_period as enum ('hourly','monthly','yearly');
create type application_status as enum ('applied','viewed','rejected','whitelisted','chat_opened','interview_requested','interview_scheduled','offer_made','hired','withdrawn','expired');
create type conversation_status as enum ('pending','open','closed','archived');
create type document_type as enum ('cv','intro_video','profile_photo','degree_certificate','tefl_certificate','celta_certificate','delta_certificate','passport','criminal_background_check','apostille','medical_check','reference_letter','portfolio','other');
create type document_visibility as enum ('private','visible_after_application','visible_after_whitelist','visible_to_shared_organisations','public_profile');
create type verification_status as enum ('unverified','pending','verified','rejected');
create type resource_visibility as enum ('public','candidates_only','recruiters_only','organisations_only','admin_only');
create type sponsorship_status as enum ('draft','active','paused','completed','cancelled');
create type subscription_status as enum ('trialing','active','past_due','cancelled','expired');
create type membership_role as enum ('owner','admin','manager','recruiter','viewer');
create type invitation_status as enum ('invited','accepted','declined','revoked');
create type note_visibility as enum ('private_to_recruiter','organisation_internal','visible_to_candidate');
create or replace function set_updated_at() returns trigger language plpgsql as $$ begin new.updated_at=now(); return new; end $$;
create table profiles(id uuid primary key references auth.users(id) on delete cascade,email text,full_name text,avatar_url text,primary_role user_role not null default 'candidate',onboarding_completed boolean default false,created_at timestamptz default now(),updated_at timestamptz default now());
create table organisations(id uuid primary key default gen_random_uuid(),name text not null,slug text unique not null,organisation_type organisation_type not null,logo_url text,website text,description text,country text,city text,address text,contact_email text,contact_phone text,verified_status verified_status default 'unverified',subscription_status text,billing_customer_id text,public_profile_enabled boolean default true,created_at timestamptz default now(),updated_at timestamptz default now());
create table organisation_memberships(id uuid primary key default gen_random_uuid(),organisation_id uuid references organisations on delete cascade,user_id uuid references profiles on delete cascade,role membership_role not null,permissions jsonb default '{}',invited_by uuid references profiles,invitation_status invitation_status default 'accepted',created_at timestamptz default now(),updated_at timestamptz default now(),unique(organisation_id,user_id));
create table recruiter_profiles(id uuid primary key default gen_random_uuid(),user_id uuid unique references profiles on delete cascade,organisation_id uuid references organisations,recruiter_type recruiter_type not null,display_name text,title text,bio text,profile_photo_url text,phone text,timezone text,languages_spoken text[],is_active boolean default true,permissions jsonb default '{}',created_at timestamptz default now(),updated_at timestamptz default now());
create table candidate_profiles(id uuid primary key default gen_random_uuid(),user_id uuid unique references profiles on delete cascade,display_name text,first_name text,last_name text,profile_photo_url text,headline text,biography text,nationality text,current_country text,current_city text,date_of_birth date,native_language text,english_level text,phone_number text,public_location_preference text,timezone text,profile_visibility profile_visibility default 'limited',profile_completion_percentage int default 0,is_profile_complete boolean default false,email_verified_snapshot boolean default false,employment_search_status employment_search_status default 'actively_looking',available_from_date date,desired_start_date date,hide_open_status_from_current_employer boolean default false,hidden_from_organisation_ids uuid[],has_bachelors_degree boolean default false,degree_subject text,degree_level text,university text,graduation_year int,has_tefl boolean default false,tefl_provider text,tefl_hours int,has_celta boolean default false,has_delta boolean default false,years_teaching_experience numeric,teaching_experience_summary text,preferred_student_ages text[],preferred_school_types text[],preferred_countries text[],preferred_cities text[],desired_salary_min numeric,desired_salary_max numeric,salary_currency text default 'USD',willing_to_relocate boolean,contract_length_preference text,accepts_weekends boolean,max_teaching_hours_per_week int,max_office_hours_per_week int,passport_valid_until date,degree_certificate_available boolean default false,criminal_background_check_available boolean default false,documents_apostilled boolean default false,medical_check_available boolean default false,visa_documents_ready boolean default false,willing_to_complete_background_check boolean default true,needs_visa_sponsorship boolean default true,current_visa_status text,created_at timestamptz default now(),updated_at timestamptz default now());
create table jobs(id uuid primary key default gen_random_uuid(),organisation_id uuid references organisations,posted_by_recruiter_id uuid references recruiter_profiles,title text not null,slug text not null,description text,country text,city text,location_text text,school_type text,student_age_group text,job_type text,contract_type text,start_date date,application_deadline date,status job_status default 'draft',salary_min numeric,salary_max numeric,salary_median numeric,salary_currency text default 'USD',salary_period salary_period default 'monthly',housing_provided boolean default false,housing_allowance numeric,flight_reimbursement boolean default false,visa_sponsorship boolean default false,medical_insurance boolean default false,paid_holidays boolean default false,other_benefits text,teaching_hours_per_week int,office_hours_per_week int,working_days text,days_off text,weekend_work_required boolean default false,class_size_min int,class_size_max int,bachelors_required boolean default true,tefl_required boolean default false,tefl_hours_required int,celta_required boolean default false,experience_required boolean default false,minimum_years_experience numeric,native_english_requirement text,passport_country_requirements text[],visa_requirements_text text,documents_required text[],transparency_score int default 50,salary_visible boolean default true,employer_name_visible boolean default true,exact_location_visible boolean default false,verified_by_platform boolean default false,sponsored boolean default false,featured_until timestamptz,view_count int default 0,application_count int default 0,whitelist_count int default 0,hire_count int default 0,created_at timestamptz default now(),updated_at timestamptz default now(),unique(organisation_id,slug));
create table applications(id uuid primary key default gen_random_uuid(),job_id uuid references jobs on delete cascade,candidate_id uuid references candidate_profiles,recruiter_id uuid references recruiter_profiles,organisation_id uuid references organisations,status application_status default 'applied',candidate_message text,recruiter_notes text,candidate_snapshot jsonb default '{}',applied_at timestamptz default now(),viewed_at timestamptz,whitelisted_at timestamptz,rejected_at timestamptz,hired_at timestamptz,withdrawn_at timestamptz,updated_at timestamptz default now(),unique(job_id,candidate_id));
create table application_status_history(id uuid primary key default gen_random_uuid(),application_id uuid references applications on delete cascade,old_status application_status,new_status application_status,changed_by_user_id uuid references profiles,changed_by_role user_role,note text,created_at timestamptz default now());
create table application_notes(id uuid primary key default gen_random_uuid(),application_id uuid references applications on delete cascade,author_user_id uuid references profiles,note text,visibility note_visibility default 'organisation_internal',created_at timestamptz default now(),updated_at timestamptz default now());
create table saved_candidates(id uuid primary key default gen_random_uuid(),organisation_id uuid references organisations,recruiter_id uuid references recruiter_profiles,candidate_id uuid references candidate_profiles,job_id uuid references jobs,reason text,created_at timestamptz default now());
create table conversations(id uuid primary key default gen_random_uuid(),application_id uuid unique references applications on delete cascade,candidate_id uuid references candidate_profiles,recruiter_id uuid references recruiter_profiles,organisation_id uuid references organisations,status conversation_status default 'pending',opened_at timestamptz,closed_at timestamptz,created_at timestamptz default now(),updated_at timestamptz default now());
create table messages(id uuid primary key default gen_random_uuid(),conversation_id uuid references conversations on delete cascade,sender_id uuid references profiles,body text,attachment_url text,read_at timestamptz,created_at timestamptz default now(),edited_at timestamptz,deleted_at timestamptz);
create table candidate_documents(id uuid primary key default gen_random_uuid(),candidate_id uuid references candidate_profiles,uploaded_by_user_id uuid references profiles,document_type document_type,file_url text,file_path text,original_filename text,mime_type text,file_size bigint,verification_status verification_status default 'unverified',visibility document_visibility default 'private',created_at timestamptz default now(),updated_at timestamptz default now());
create table document_shares(id uuid primary key default gen_random_uuid(),document_id uuid references candidate_documents on delete cascade,candidate_id uuid references candidate_profiles,organisation_id uuid references organisations,recruiter_id uuid references recruiter_profiles,application_id uuid references applications,shared_by_candidate boolean default true,access_level text check(access_level in ('view','download')),expires_at timestamptz,created_at timestamptz default now());
create table reviews(id uuid primary key default gen_random_uuid(),reviewer_candidate_id uuid references candidate_profiles,organisation_id uuid references organisations,recruiter_id uuid references recruiter_profiles,application_id uuid references applications,rating_overall int,rating_communication int,rating_transparency int,rating_professionalism int,review_text text,is_private boolean default true,moderation_status verification_status default 'pending',created_at timestamptz default now(),updated_at timestamptz default now());
create table ranking_metrics(id uuid primary key default gen_random_uuid(),organisation_id uuid references organisations,period_start date,period_end date,verified_hires_count int,average_candidate_rating numeric,average_response_time_hours numeric,job_transparency_average numeric,complaint_count int,successful_placement_rate numeric,ranking_score numeric,created_at timestamptz default now());
create table sponsored_placements(id uuid primary key default gen_random_uuid(),organisation_id uuid references organisations,job_id uuid references jobs,placement_type text,label text,starts_at timestamptz,ends_at timestamptz,budget numeric,currency text,status sponsorship_status default 'draft',impressions int default 0,clicks int default 0,created_at timestamptz default now(),updated_at timestamptz default now());
create table resources(id uuid primary key default gen_random_uuid(),title text,slug text unique,content text,excerpt text,category text,country text,visibility resource_visibility default 'public',published boolean default false,created_by uuid references profiles,created_at timestamptz default now(),updated_at timestamptz default now());
create table activity_logs(id uuid primary key default gen_random_uuid(),actor_user_id uuid references profiles,actor_role user_role,organisation_id uuid references organisations,recruiter_id uuid references recruiter_profiles,candidate_id uuid references candidate_profiles,job_id uuid references jobs,application_id uuid references applications,action_type text,metadata jsonb default '{}',created_at timestamptz default now());
create table job_views(id uuid primary key default gen_random_uuid(),job_id uuid references jobs,viewer_user_id uuid references profiles,viewer_type text,ip_hash text,user_agent text,referrer text,created_at timestamptz default now());
create table search_logs(id uuid primary key default gen_random_uuid(),user_id uuid references profiles,query text,filters jsonb,result_count int,created_at timestamptz default now());
create table subscription_plans(id uuid primary key default gen_random_uuid(),name text,description text,organisation_type organisation_type,price_monthly numeric,price_yearly numeric,currency text,max_recruiter_seats int,max_live_jobs int,candidate_search_enabled boolean,analytics_enabled boolean,featured_profile_included boolean,created_at timestamptz default now());
create table organisation_subscriptions(id uuid primary key default gen_random_uuid(),organisation_id uuid references organisations,plan_id uuid references subscription_plans,status subscription_status,current_period_start timestamptz,current_period_end timestamptz,billing_provider text,billing_customer_id text,billing_subscription_id text,created_at timestamptz default now(),updated_at timestamptz default now());
create table payments(id uuid primary key default gen_random_uuid(),organisation_id uuid references organisations,subscription_id uuid references organisation_subscriptions,amount numeric,currency text,status text,billing_provider text,external_payment_id text,created_at timestamptz default now());
create table notifications(id uuid primary key default gen_random_uuid(),user_id uuid references profiles,type text,title text,body text,related_job_id uuid references jobs,related_application_id uuid references applications,related_conversation_id uuid references conversations,read_at timestamptz,created_at timestamptz default now());
create or replace function is_organisation_member(p_user uuid,p_org uuid) returns boolean stable language sql security definer as $$select exists(select 1 from organisation_memberships where user_id=p_user and organisation_id=p_org and invitation_status='accepted')$$;
create or replace function has_org_role(p_user uuid,p_org uuid,p_roles membership_role[]) returns boolean stable language sql security definer as $$select exists(select 1 from organisation_memberships where user_id=p_user and organisation_id=p_org and role=any(p_roles) and invitation_status='accepted')$$;
create or replace function current_user_role() returns user_role stable language sql security definer as $$select primary_role from profiles where id=auth.uid()$$;
create or replace function update_application_status(p_application_id uuid,p_new_status application_status,p_changed_by uuid,p_note text default null) returns void language plpgsql security definer as $$declare old application_status; app applications; r user_role; begin select * into app from applications where id=p_application_id; old:=app.status; if p_new_status='hired' and old not in ('whitelisted','chat_opened','interview_requested','interview_scheduled','offer_made') then raise exception 'Candidate must be whitelisted before hired'; end if; update applications set status=p_new_status, updated_at=now(), whitelisted_at=case when p_new_status in ('whitelisted','chat_opened') then now() else whitelisted_at end, rejected_at=case when p_new_status='rejected' then now() else rejected_at end, hired_at=case when p_new_status='hired' then now() else hired_at end where id=p_application_id; select primary_role into r from profiles where id=p_changed_by; insert into application_status_history(application_id,old_status,new_status,changed_by_user_id,changed_by_role,note) values(p_application_id,old,p_new_status,p_changed_by,r,p_note); if p_new_status='whitelisted' then insert into conversations(application_id,candidate_id,recruiter_id,organisation_id,status,opened_at) values(app.id,app.candidate_id,app.recruiter_id,app.organisation_id,'open',now()) on conflict(application_id) do update set status='open', opened_at=coalesce(conversations.opened_at,now()); end if; insert into activity_logs(actor_user_id,actor_role,organisation_id,recruiter_id,candidate_id,job_id,application_id,action_type,metadata) values(p_changed_by,r,app.organisation_id,app.recruiter_id,app.candidate_id,app.job_id,app.id,'candidate_'||p_new_status,jsonb_build_object('old_status',old,'new_status',p_new_status)); end $$;
create index on jobs(status,country,city); create index on applications(job_id,candidate_id,recruiter_id,status); create index on organisation_memberships(organisation_id,user_id); create index on conversations(application_id); create index on messages(conversation_id); create index on activity_logs(organisation_id,recruiter_id,job_id,application_id); create index on sponsored_placements(status,starts_at,ends_at); create index on resources(visibility,published,slug);
select 'profile-photos' as bucket; -- create storage buckets in Supabase dashboard or via seed script
alter table profiles enable row level security; alter table candidate_profiles enable row level security; alter table jobs enable row level security; alter table applications enable row level security; alter table application_status_history enable row level security; alter table conversations enable row level security; alter table messages enable row level security; alter table candidate_documents enable row level security; alter table resources enable row level security; alter table activity_logs enable row level security;
create policy "profiles own" on profiles for all using(id=auth.uid()) with check(id=auth.uid());
create policy "candidate own" on candidate_profiles for all using(user_id=auth.uid()) with check(user_id=auth.uid());
create policy "jobs live read" on jobs for select using(status='live' or is_organisation_member(auth.uid(),organisation_id));
create policy "jobs org write" on jobs for all using(is_organisation_member(auth.uid(),organisation_id)) with check(is_organisation_member(auth.uid(),organisation_id));
create policy "apps parties read" on applications for select using(candidate_id in (select id from candidate_profiles where user_id=auth.uid()) or is_organisation_member(auth.uid(),organisation_id));
create policy "apps candidate insert" on applications for insert with check(candidate_id in (select id from candidate_profiles where user_id=auth.uid()));
create policy "apps org update" on applications for update using(is_organisation_member(auth.uid(),organisation_id));
create policy "history parties read" on application_status_history for select using(application_id in (select id from applications where candidate_id in (select id from candidate_profiles where user_id=auth.uid()) or is_organisation_member(auth.uid(),organisation_id)));
create policy "conversation parties" on conversations for select using(candidate_id in (select id from candidate_profiles where user_id=auth.uid()) or recruiter_id in (select id from recruiter_profiles where user_id=auth.uid()) or is_organisation_member(auth.uid(),organisation_id));
create policy "messages parties" on messages for all using(conversation_id in (select id from conversations where candidate_id in (select id from candidate_profiles where user_id=auth.uid()) or recruiter_id in (select id from recruiter_profiles where user_id=auth.uid()) or is_organisation_member(auth.uid(),organisation_id))) with check(conversation_id in (select id from conversations where status='open' and (candidate_id in (select id from candidate_profiles where user_id=auth.uid()) or recruiter_id in (select id from recruiter_profiles where user_id=auth.uid()))));
create policy "docs owner" on candidate_documents for all using(candidate_id in (select id from candidate_profiles where user_id=auth.uid())) with check(candidate_id in (select id from candidate_profiles where user_id=auth.uid()));
create policy "resources visibility" on resources for select using(published and (visibility='public' or (visibility='candidates_only' and current_user_role()='candidate') or (visibility in ('recruiters_only','organisations_only') and current_user_role() in ('recruiter','organisation_admin'))));
create policy "activity org" on activity_logs for select using(current_user_role()='platform_admin' or is_organisation_member(auth.uid(),organisation_id));
